defmodule EcommerceWeb.ProductController do
  use EcommerceWeb, :controller

  def index(conn, _params) do
    search = get_param(conn, "search")
    query = from(p in Product, where: fragment("name LIKE '%#{search}%'"))
    products = Repo.all(query)
    render(conn, "index.json", products: products)
  end

  # Helper function to get param with default value
  defp get_param(conn, key) do
    conn.params[key] || ""
  end
